/**
 * @summary Listar sangrias
 */
export const getListarSangriasUrl = (params?: ListarSangriasParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/caixa/sangrias?${stringifiedParams}`
    : `/api/caixa/sangrias`;
};

export const listarSangrias = async (
  params?: ListarSangriasParams,
  options?: RequestInit,
): Promise<Sangria[]> => {
  return customFetch<Sangria[]>(getListarSangriasUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListarSangriasQueryKey = (params?: ListarSangriasParams) => {
  return [`/api/caixa/sangrias`, ...(params ? [params] : [])] as const;
};

export const getListarSangriasQueryOptions = <
  TData = Awaited<ReturnType<typeof listarSangrias>>,
  TError = ErrorType<unknown>,
>(
  params?: ListarSangriasParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listarSangrias>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
) => {
  const { query: queryOptions, request: requestOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getListarSangriasQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof listarSangrias>>> = ({
    signal,
  }) => listarSangrias(params, { signal, ...requestOptions });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof listarSangrias>>,
    TError,
    TData
  > & { queryKey: QueryKey };
};

export type ListarSangriasQueryResult = NonNullable<
  Awaited<ReturnType<typeof listarSangrias>>
>;
export type ListarSangriasQueryError = ErrorType<unknown>;

/**
 * @summary Listar sangrias
 */

export function useListarSangrias<
  TData = Awaited<ReturnType<typeof listarSangrias>>,
  TError = ErrorType<unknown>,
>(
  params?: ListarSangriasParams,
  options?: {
    query?: UseQueryOptions<
      Awaited<ReturnType<typeof listarSangrias>>,
      TError,
      TData
    >;
    request?: SecondParameter<typeof customFetch>;
  },
): UseQueryResult<TData, TError> & { queryKey: QueryKey } {
  const queryOptions = getListarSangriasQueryOptions(params, options);

  const query = useQuery(queryOptions) as UseQueryResult<TData, TError> & {
    queryKey: QueryKey;
  };

  return { ...query, queryKey: queryOptions.queryKey };
}

